import type { Interpretation } from "./types";

export const ASPECTS: Record<string, Interpretation> = {
  "sun-moon-conjunction": { title: "Sun conjunct Moon", body: "You were born near a new moon, and it shows: what you want and what you need speak with **one voice**. There is no committee meeting between your ambition and your comfort — they left the house together this morning. In daily life this looks like momentum other people have to manufacture: you decide, you feel settled about it, you go. Your instincts and your intentions rarely contradict each other, which makes you unusually whole and occasionally unusually stubborn.\n\nThe growth edge is **perspective**. A self this seamless can forget to step outside and look back, because nothing inside is arguing loudly enough to make you check. Borrow other people's eyes on purpose — ask the friend who sees you differently, keep the mirror honest. Your unity is real power; **reflection is what keeps it from becoming a sealed room**." },
  "sun-moon-square": { title: "Sun square Moon", body: "The life you are building and the comfort you crave keep pulling in different directions, and you have felt that tug since childhood — maybe as two parents with different weather, maybe as **ambition and belonging refusing to share a room**. When you chase the goal, something homesick tugs at your sleeve. When you rest into safety, something restless paces. Neither voice is wrong; they are just not yet in conversation.\n\nHere is what this square is actually building: a person who can **hold complexity without splitting**. You grow by negotiating between the two, not by sacrificing one to feed the other. Practice letting a decision take longer so both selves get a vote. People who have done this work become the ones others trust with their own contradictions — **friction, metabolized, becomes wisdom**." },
  "sun-moon-opposition": { title: "Sun opposite Moon", body: "You were born under full moon logic: purpose on one side of the sky, need on the other, each lighting the other from across a distance. In lived terms, **relationships are your mirror** — you often discover what you actually feel by watching it reflected in someone close to you. There can be a see-saw quality: when your public direction is strong, your private life asks for tending, and vice versa. You are built for dialogue, inside and out.\n\nThe art is **integration, not choosing sides**. You do not have to abandon the life you are making to honor the self who needs rest, ritual, and softness — and you do not have to shrink your purpose to be loved. Let the two poles write letters. The full moon is not a conflict; **it is illumination**, and you carry it." },
  "sun-mercury-conjunction": { title: "Sun conjunct Mercury", body: "Your mind and your identity are welded together, so speaking a thought feels like **showing your face**. Ideas arrive fast and arrive personal; when someone critiques your reasoning, it can land like a critique of your existence. The gift side is real: you articulate yourself with a directness most people envy, and your voice — written, spoken, signed — is one of the truest records of who you are.\n\nThe practice is **a little daylight between you and your opinions**. Let an idea be examined without feeling examined yourself; let a draft be wrong without you being wrong. Try holding a belief at arm's length for one conversation and see what survives. What survives is genuinely yours. **You are not your first sentence** — you are the mind that keeps revising it." },
  "sun-mercury-square": { title: "Sun square Mercury", body: "Who you are and how you explain yourself keep arguing, and you feel it as a kind of chronic mistranslation: you say the thing sideways before you say it true, then hear your own words and think, that is not what I meant. The self is clear; **the transmission crackles**. This is maddening and it is also the exact pressure that makes writers, editors, and people with hard-won precision.\n\nThe practice is **revision as devotion**. Write it, wait, rewrite it. Slow your speech by half a beat and let the truer sentence catch up. Over years, this grind produces something rarer than easy eloquence: a voice that has been tested against its own misfires. **You earned every clear sentence you have** — and it shows in how they land." },
  "sun-mercury-opposition": { title: "Sun opposite Mercury", body: "Your sense of self and your inner narrator sit at opposite ends of a long table, debating. In lived life this means other people's words can feel like **verdicts on your identity** — a stray comment echoes for days, a compliment gets cross-examined. You may also notice you understand yourself best mid-conversation, as if your thoughts need another person's presence to fully form.\n\nThat is not weakness; it is your design. **You think best out loud, in company.** The growth edge is learning to hear feedback as data rather than judgment — information about how you are landing, not a ruling on whether you deserve to exist. Choose interlocutors who argue in good faith, and this opposition becomes its gift form: **genuine dialogue**, the kind that leaves both people changed." },
  "sun-venus-conjunction": { title: "Sun conjunct Venus", body: "Charm is not something you perform; it is fused to your core. People warm to you before you have finished a sentence, and you have a native instinct for **beauty as a way of being** — how a room feels, how a gesture lands, how to make someone feel chosen. You want to be loved for exactly who you are, and mostly you are, which is precisely why rejection cuts so unusually deep: it feels like a verdict on your whole self.\n\nThe work is anchoring your worth in **something steadier than being adored**. Make things. Keep promises to yourself. Notice that your value holds on the days no one is looking. When your shine stops depending on the audience, it gets brighter, not dimmer — **grace with a spine** is the mature form of this gift." },
  "sun-venus-square": { title: "Sun square Venus", body: "What you want to become and what keeps the peace are often two different choices, and you feel the grind every time you pick. You may swing between **pleasing others and asserting yourself**, over-accommodating until something in you snaps upright. Your taste is genuinely refined by this friction — you know the difference between harmony that is real and harmony that is purchased with pieces of yourself.\n\nThe quiet triumph of this square is learning that **love does not require self-erasure**. The people worth keeping can survive your no. Practice one honest preference a day: the restaurant you actually want, the plan you actually decline. Each small assertion teaches your nervous system that belonging and selfhood can coexist — and that is when your relationships stop being performances and start being **places you actually live**." },
  "sun-venus-opposition": { title: "Sun opposite Venus", body: "Your identity and your longing for connection face each other across a divide, and partners often carry the qualities you have not yet claimed — the ease, the beauty, the social grace you admire at close range. You tend to **meet your own loveliness in other people first**, falling for what is secretly yours. Relationships feel central to your becoming, sometimes to the point where you cannot find yourself without one.\n\nThe balance point is **loving without outsourcing your shine**. When you catch yourself idolizing someone's charm, ask what it is showing you about your own unlived elegance — then live a little of it. This opposition matures into something beautiful: partnership between two whole people, where admiration flows both directions and **nobody has to be the mirror full-time**." },
  "sun-mars-conjunction": { title: "Sun conjunct Mars", body: "Will and identity run on the same current in you, so **wanting something and becoming someone are one motion**. You act fast, recover fast, and rarely stand at a crossroads wondering what you would do — you are already doing it. People experience you as vivid, direct, sometimes a lot; you experience hesitation in others as a foreign language. Courage is not a decision for you. It is a default.\n\nThe edge to tend: heat this direct can **scorch before you notice you are angry**. Anger often registers as certainty or urgency first, and by the time you feel the flame, someone else already has. Build a half-second of noticing between impulse and action. Aimed consciously, your fire clears paths for people with less of it — **that is what it is for**." },
  "sun-mars-square": { title: "Sun square Mars", body: "Your drive keeps colliding with your sense of who you are supposed to be, and the sparks are real fuel. Frustration is your raw material — it flares exactly where you are **underliving**, pointing at the room in your life that is too small. You may have learned early that your force was too much for someone, and spent years throttling an engine that was never the problem.\n\nThe work is giving the fire a **worthy assignment**. Trained toward a goal that actually matters to you, this square builds relentless, earned confidence — the kind that has been tested against its own combustion. Move your body regularly; unspent drive turns inward and calls itself anxiety. And when frustration rises, ask it what it wants built. **It always knows.**" },
  "sun-mars-opposition": { title: "Sun opposite Mars", body: "Conflict finds you, and it is not bad luck — you are learning what to do with force, and life keeps sending tutors. Other people's aggression often mirrors **a fire you have not fully owned**: the pushy colleague, the combative stranger, the friend who picks the fight you were quietly avoiding. If you disown your own assertion, you will keep meeting it secondhand, wearing someone else's face.\n\nThe invitation is to **claim your force cleanly**: say the direct thing early, want what you want out loud, stop apologizing for taking up space. Watch what happens — the battles thin out, because you are no longer outsourcing the war. What remains is something rarer: the capacity for honest confrontation that ends in **more respect, not less**." },
  "sun-jupiter-conjunction": { title: "Sun conjunct Jupiter", body: "You were built at a generous scale: **big faith, big appetite**, a horizon that keeps moving because you keep walking toward it. Luck tends to follow your confidence — doors open partly because you assume they will, and people say yes to you because your belief is contagious. You make rooms feel larger. Whatever you touch, you instinctively want to grow it, share it, take it further.\n\nThe discipline is **discernment**, since not every open door deserves you walking through it. Your yes is powerful, which means it needs a budget. Practice letting three good opportunities pass to keep one great one whole. Abundance that chooses is more potent than abundance that scatters — and your particular gift, at full maturity, is **generosity with excellent aim**." },
  "sun-jupiter-square": { title: "Sun square Jupiter", body: "Your reach keeps exceeding your grasp — on purpose. This square inflates plans past their scaffolding, then teaches you, project by project, where the real edges are. You promise from the summit and deliver from the trail, and the gap can embarrass you into thinking you are unreliable. You are not. **You are calibrating**, and calibration takes reps.\n\nOvercommitment is the lesson, not the sentence. The practice is **sizing your promises**: say yes to the vision, then cut the first version in half before you announce it. Keep the faith — it is your engine — but give it a fuel gauge. When your natural abundance learns to keep its word, people stop bracing when you dream out loud and start **building alongside you**." },
  "sun-jupiter-opposition": { title: "Sun opposite Jupiter", body: "Meaning always seems to live somewhere else: another city, another teacher, another version of you, eighteen months from now. The pull outward is real — you genuinely grow through distance, difference, and people whose maps look nothing like yours. But left unexamined, this opposition can turn your actual life into **a waiting room for the real one**.\n\nThe balance is **bringing the pilgrimage home**. The vastness you keep chasing is a capacity, not a location; it travels with you or it does not exist. Practice finding the enormous inside the ordinary — the philosophy in your kitchen, the teacher in your Tuesday. When you stop deferring your life to the horizon, the horizon starts arriving on its own, and **everywhere becomes somewhere**." },
  "sun-saturn-conjunction": { title: "Sun conjunct Saturn", body: "You came in with gravity — an early seriousness that others mistook for coldness and you experienced as weight. Somewhere young, you concluded that being counted on was the price of being kept, and you have been **paying dues on your own existence** ever since. Achievement matters to you at the level of proof: I built this, therefore I am allowed to be here.\n\nHere is the tenderness in it: **time is your ally**. This aspect ripens. The authority you are building — slow, tested, unfakeable — becomes more real every year, while borrowed confidence around you expires. The practice is letting some things be unearned: rest you did not deserve first, love that arrived without an invoice. You were allowed here from the start. **The work was never the admission fee.**" },
  "sun-saturn-square": { title: "Sun square Saturn", body: "An inner critic audits everything you attempt — before, during, and after — and the grind is exhausting until you realize it is also **a forge**. Doubt makes you thorough. Obstacles make you durable. You rarely trust your own progress, which means you check it twice, which means it holds. The people who move faster than you are usually building on sand.\n\nYour task is separating **the useful standard from the inherited verdict** — the voice that says do it well versus the older voice that says you will never be enough. One is a tool; the other is a wound wearing a clipboard. Keep the standard, retire the verdict. Ship the work at 90 percent and watch the world not end. **Slowly earned confidence is the only kind that cannot be repossessed.**" },
  "sun-saturn-opposition": { title: "Sun opposite Saturn", body: "Authority figures loom large in your story — gatekeepers, judges, the boss or parent or institution whose approval once felt like oxygen. You keep meeting the wall in other people's hands: the one who says not yet, not you, **not like that**. Some of those limits were real. Many were a mirror for a permission you had not yet granted yourself.\n\nThe opposition asks you to **internalize the judge and retire the courtroom**. Become the credible authority you kept auditioning for: set your own standards, meet them, and let that be the ruling. External permission loses its grip the day you stop applying for it. What remains is sturdier — respect between you and the structures of the world, negotiated **as equals, not supplicants**." },
  "sun-uranus-conjunction": { title: "Sun conjunct Uranus", body: "Your identity has lightning in it. You are wired to interrupt patterns — including your own — and predictability feels less like safety than **slow suffocation**. People call you ahead of your time because you are; you see the exit from arrangements everyone else still thinks are load-bearing. If you have ever rebuilt yourself in a way that startled the people who thought they knew you, that was not a phase. That was the design.\n\nDifference, here, is **inheritance, not deviation** — you come from every person who refused the given script. The craft is choosing your revolutions instead of detonating whatever gets comfortable. Ask, before you break it: is this a cage or just a container? Cages, break freely. Containers, renovate. **Your strangeness is a compass; let it steer, not just startle.**" },
  "sun-uranus-square": { title: "Sun square Uranus", body: "Every time your life settles into a shape, something in you reaches for the exit. The job stabilizes and you fantasize resignation; the relationship deepens and you eye the door — not because anything is wrong, but because **settled and trapped feel identical** from inside your nervous system. This square grinds between commitment and freedom, and the friction is generative if you let it redesign rather than destroy.\n\nThe growth is learning to **change things without burning them down**. Build revolutions into the structure: sabbaticals, renegotiations, rooms of your own. Give your restlessness scheduled work and it stops staging ambushes. You are not fickle. You are someone whose aliveness requires motion — **honor that on purpose and it becomes innovation instead of wreckage**." },
  "sun-uranus-opposition": { title: "Sun opposite Uranus", body: "Disruption tends to arrive through other people: the wildcard friend, the sudden reversal, the partner who upends the plan the week you finally relaxed. It can feel like the chaos is happening to you — but look closer at the pattern. The lightning keeps striking near you because **it is yours**, projected outward, carried by whoever was willing to hold your unclaimed strangeness.\n\nThe move is to **own your originality directly**. Say the weird idea yourself. Make the unconventional choice before someone forces it. When you become the source of your own surprises, the ambient chaos gets noticeably quieter — the wildcards stop auditioning for the role you have finally taken. What remains is the good part: **a life that keeps waking itself up**, on your terms." },
  "sun-neptune-conjunction": { title: "Sun conjunct Neptune", body: "Your sense of self has soft, watercolor edges. You absorb rooms, dreams, and other people's weather, which makes you compassionate, imaginative, and occasionally **hard to locate** — even to yourself. Who am I today can be a real question, not a crisis but a tide. You were probably praised for your empathy long before anyone taught you it needed a container.\n\nArt and devotion give the mist a vessel: make things, keep a practice, let something larger than personality hold you. And know this — **boundaries are not a betrayal of your sensitivity; they are its container**. A self with edges can afford to stay open. Practice saying where you end, gently and often. The dissolving is a gift when it is chosen. **Chosen is the whole work.**" },
  "sun-neptune-square": { title: "Sun square Neptune", body: "Who you are and who you imagine being keep dissolving into each other, and the fog can feel like failure — plans that lose their outline, ambitions that go soft when you reach for them, a self-image that will not hold still for the photograph. It is not failure. It is **unformed vision**, and the friction is how it forms.\n\nThe practice is testing dreams against reality until the ones that survive become genuinely yours: small experiments instead of grand vows, one concrete step instead of another season of longing. Beware the escape hatches — numbing, fantasy, the beautiful excuse. **Discernment is your devotion here.** Every ideal that survives contact with the actual world stops being fog and becomes light you can work by, and that light is **earned and unmistakable**." },
  "sun-neptune-opposition": { title: "Sun opposite Neptune", body: "You meet the sublime through other people — and sometimes the con artist too, since **idealizing people is your particular undertow**. You see the best in someone, then quietly agree to unsee the rest, and the disappointment when reality surfaces can feel like drowning. What you keep worshiping in them is a light you have not claimed: the artist, the mystic, the beautiful dreamer are all roles you keep casting instead of playing.\n\nThis opposition is patiently teaching **clear seeing, not cynicism**. You can honor someone's shimmer and still count their actions. You can keep your faith and check the references. And you can bring the projected radiance home — make the art, keep the practice, be the one who shimmers. **Devotion with open eyes is the deepest kind.**" },
  "sun-pluto-conjunction": { title: "Sun conjunct Pluto", body: "There is a depth charge in your identity. You do not do casual selfhood; you metabolize, transform, and rise differently — **again and again**, whole eras of you composted into the next version. Your presence carries weight others feel before you speak, and people either lean toward it or brace against it. You have likely survived something that would have ended a lighter person, and the survival is written into how you hold a room.\n\nThe work is wielding that intensity as **medicine rather than control**. Power this concentrated will find an outlet — choose depth work, art, advocacy, the truth no one else will say. Watch the urge to manage outcomes and people when you feel unsafe. You do not need leverage to be unleavable. **Your realness is the magnet; trust it.**" },
  "sun-pluto-square": { title: "Sun square Pluto", body: "Life keeps handing you power struggles that are secretly initiations. The controlling authority, the crisis that strips you down, the season where an identity you built stops fitting and must be dismantled — this square insists that something in you be **rebuilt more than once**, and resisting the process is most of what makes it hurt. You are not being punished. You are being made load-bearing.\n\nEach reconstruction leaves you **less breakable and more honest** about what actually drives you. The practice is choosing your transformations before circumstances choose them: do the shadow work voluntarily, release the obsolete self before it is torn away. Fate here is material, not sentence. People who work this square become the ones others call when everything falls apart — because you know, from experience, that **falling apart is survivable and sometimes holy**." },
  "sun-pluto-opposition": { title: "Sun opposite Pluto", body: "Intensity tends to arrive wearing someone else's face: the controlling boss, the consuming lover, the rival who sees too much and uses it. Relationships can feel like power negotiations you never signed up for — yet keep finding yourself in. Here is the hidden mechanism: these encounters mirror **your own buried force**, the part of you that wants, drives, and dominates, exiled early because it frightened someone.\n\nReclaim it. Not by becoming ruthless, but by admitting the full voltage of your will and giving it honest work. When you own your power, you stop attracting people who wield it over you — **the vacancy closes**. What replaces the battleground is rare: relationships of real, unflinching depth, where two undiminished people meet and **nobody has to shrink to stay**." },
  "moon-mercury-conjunction": { title: "Moon conjunct Mercury", body: "Feeling and language are fused in you, so your emotions arrive **already narrated** — you know the word for the ache before the ache has finished forming. This makes you a natural confidant, a storyteller, the friend who can name what everyone else only senses. Your memory is emotional and your speech is intimate; even your small talk has an undertow of realness.\n\nThe practice is remembering that **some feelings want to be felt before they are explained**. Narration can become a way of keeping experience at podcast distance — described, but not inhabited. Once in a while, put the pen down and just let the wave land wordlessly. Then write. Your gift is translation between heart and language; **the translation is truest when you have actually visited both countries**." },
  "moon-mercury-square": { title: "Moon square Mercury", body: "Your head and your heart file separate reports, and the discrepancy can make you doubt both. You reason your way to a decision and your body refuses it; you feel something clearly and your mind cross-examines it into fog. This grind is not brokenness — it is **two intelligences that have not yet learned each other's language**, and you are the translator being trained.\n\nJournaling and honest conversation are where the treaty gets negotiated: write until the feeling has words, speak until the logic has warmth. Over time you develop a rare skill — **fluency in both logic and feeling**, and the ability to hear when someone else's are at war. What began as inner static becomes your profession-grade gift: **you can help hearts and minds trust each other**, starting with your own." },
  "moon-mercury-opposition": { title: "Moon opposite Mercury", body: "You swing between analyzing your feelings and feeling your analysis, rarely doing both at once — and the people close to you often end up voicing **the half you are ignoring**. When you are all logic, someone arrives weeping the emotion you filed away; when you are drowning in mood, someone offers the cold summary you refused to write. It can feel like being contradicted. It is actually being completed.\n\nThe balance point is **a conversation where mind and mood get equal airtime**, inside you and out loud. Practice saying both sentences: here is what I think, and here is what I feel, without ranking them. Partnerships thrive when you stop assigning one person to be the head and one the heart. **You contain both; so do they.**" },
  "moon-venus-conjunction": { title: "Moon conjunct Venus", body: "Tenderness comes standard in you. Comfort, beauty, and affection are not luxuries but **the actual architecture of your emotional safety** — the arranged room, the good meal, the soft landing you build for the people you love, often before they know they need it. You soothe almost reflexively, and your presence reads as welcome. People exhale around you and rarely wonder why.\n\nThe growth edge is letting relationships hold **your unlovely moods too**, not just your graciousness. If care always flows outward, intimacy becomes a performance with excellent catering. Practice arriving somewhere uncurated: tired, snappish, undone, and letting yourself be tended anyway. The people worth keeping will not flinch. Being loved at your least decorative is the proof your body is waiting for — **that the welcome you give exists for you too**." },
  "moon-venus-square": { title: "Moon square Venus", body: "What you need and what you find lovely keep missing each other, so you may soothe yourself with pleasures that do not actually nourish — the purchase instead of the cry, the charming evening instead of the honest one. There can be a split between **being comfortable and being honest about desire**, a habit of performing contentment while the real need waits in the hallway.\n\nThe friction is teaching **emotional honesty about what you actually want** — which is rarely what looks best in the photograph. Practice the unglamorous ask: I need quiet, I need reassurance, I need you to stay. When you stop decorating your needs, real sweetness finally gets through, and you discover the plot twist of this square: **the true thing was more beautiful all along**." },
  "moon-venus-opposition": { title: "Moon opposite Venus", body: "You are pulled between being cared for and being desired — between the nest and the romance — and partners can seem to demand a choice: the one who feels like home but not like fire, the one who feels like fire but never like rest. You may have concluded that **comfort and passion live at different addresses**, and resigned yourself to commuting.\n\nThey do not, really. The split lives in you first: a belief that the self who needs and the self who enchants cannot be the same person in the same room. The art is letting one relationship — and one body — hold **both tenderness and beauty**. Show your beloved the unglamorous need; bring desire home to the nest. **Wholeness is the actual romance**, and you are allowed it." },
  "moon-mars-conjunction": { title: "Moon conjunct Mars", body: "Your feelings come armed. Emotion converts to action almost instantly in you — you defend before you decide to, you leap for the people you love, and your anger arrives **already standing up**. This makes you fiercely protective, quick to respond, and impossible to mistake for indifferent. The people you love are lucky in a specific way: no one has to wonder whether you would fight for them.\n\nNothing about this needs taming, only **aiming**. The heat is honest; the question is whether it advocates or erupts. Practice the three-breath pause — not to suppress the fire but to point it. When your anger learns to make requests instead of war, it becomes your most trustworthy instrument: **a heart that acts is a gift, and a heart that aims is a force**." },
  "moon-mars-square": { title: "Moon square Mars", body: "Your needs and your temper grind against each other, and vulnerability can flip into fight before you feel the switch — someone gets too close to the soft place and suddenly you are arguing about the dishes. Underneath most of your battles is a tenderness that never got safe passage. This square is teaching you that **anger is often grief in armor**.\n\nThe practice is naming the softer feeling first: I am hurt lands differently than the sharpened version, and it defuses half your wars before they start. Move your body daily — unspent charge in this aspect turns inward and gnaws. Handled honestly, you become something rare: a person whose fire **protects without burning the house down**, and whose loved ones learn that your heat and your heart are **the same loyal animal**." },
  "moon-mars-opposition": { title: "Moon opposite Mars", body: "Conflict at close range is your classroom. The people you live with and love most seem uniquely able to provoke you — the door slammed at home that would never slam at work, the fight that only this person can start. It is not proof you chose wrong. Intimacy is where your **need and assertion have not yet made peace**, and closeness turns the volume up on the negotiation.\n\nThat peace is makeable. Practice noticing what the anger is protecting — usually a need you have not voiced because voicing it feels dangerous. Say the need before the temper says it for you. Households that survive this opposition come out stronger than most: everyone in them learns that **conflict can be safe**, and that love with honest heat is **sturdier than love that never raises its voice**." },
  "moon-jupiter-conjunction": { title: "Moon conjunct Jupiter", body: "Your emotional default is abundance: big feelings, big hospitality, a heart that **assumes there is enough** and usually makes it true. People exhale around you. Jupiter loves being near the Moon — this is generosity that actually nourishes, the friend with the extra plate, the mood that lifts a whole room without trying. Your optimism is not naivety; it is a working philosophy that keeps proving itself.\n\nThe shadow is excess: soothing every ache with more of something — more food, more plans, more yes. Your comfort instinct is beautiful and it needs an editor. The practice is **sitting with enough**: letting a feeling be met rather than fed. Your generosity lands deepest when it includes limits, especially for yourself. **Abundance with boundaries is the sustainable kind** — and yours is worth sustaining." },
  "moon-jupiter-square": { title: "Moon square Jupiter", body: "Your feelings run oversized, and the urge to fix discomfort with more — more food, more plans, more promises, more people — is the grind here. A small sadness becomes a booked weekend; a real need gets buried under a celebration. **Emotional appetite is not the problem; unexamined appetite is.** You are learning the difference between filling a feeling and meeting it.\n\nThe practice is pausing at the moment of reach: what am I actually hungry for right now? Often it is rest, or witness, or a good cry — things that cannot be ordered in. When you learn to sit with enough, this square converts into its gift form: **grounded, generous warmth** that comforts others because it has stopped fleeing itself. Your bigness was never the flaw. **Unfelt feelings were.**" },
  "moon-jupiter-opposition": { title: "Moon opposite Jupiter", body: "Home pulls one way and the horizon pulls the other, and you can feel **homesick in both directions** — restless in your sanctuary, nostalgic on your adventures. In relationships, the split often gets cast: you play the optimist while someone else holds the worry, or you carry the caution while a partner floats the dreams. Whoever holds one pole, the other polarizes harder.\n\nThe balance is a life where **roots and reach feed each other**: a home that launches you, journeys that deepen your belonging. Practice holding both poles yourself — voice your own worry and your own hope in the same conversation, so nobody has to be your missing half. Growth that abandons the nest starves; a nest that forbids growth suffocates. **You are built for both, on purpose.**" },
  "moon-saturn-conjunction": { title: "Moon conjunct Saturn", body: "You learned early to ration your needs. Somewhere back there, the emotional weather taught you that asking cost too much, so **self-containment became both your armor and your loneliness** — the composed face, the handled feelings, the childhood that ended early. People read you as steady, and you are; they rarely guess what the steadiness cost.\n\nUnderneath the composure is a deeply loyal heart that takes commitment more seriously than almost anyone. The slow, worthwhile work is **letting yourself be cared for without auditing the cost** — receiving without immediately calculating repayment. Start small: accept the favor, take the offered seat, let someone see you tired. Saturn ripens everything it touches, including this: your capacity for intimacy grows with age, and the love you build late is **built to last**." },
  "moon-saturn-square": { title: "Moon square Saturn", body: "Something in you treats needing people as a debt you cannot afford. The grind between hunger and restraint built your remarkable self-sufficiency — you truly can carry more alone than most — and it also built **the wall**: the flinch before asking, the automatic I'm fine, the way you comfort everyone and go home unaccompanied by your own tenderness.\n\nThe wall was intelligent once; it kept a young heart from repeated disappointment. But the practice now is **small, low-stakes asks**: can you grab me a coffee, can you sit with me, can you read this. Each granted request is evidence against the old verdict. Slowly, the wall becomes a door — one with a good lock you control, opening onto the thing you rationed longest: **being held without earning it first**." },
  "moon-saturn-opposition": { title: "Moon opposite Saturn", body: "You keep meeting people who feel withholding — or you become the withholding one, trading places across the same cold divide. The distant partner, the conditional warmth, the love that always seems to arrive with terms attached. The pattern started long before them, in whatever early room taught you that **care and scarcity travel together**.\n\nHere is the mechanism worth seeing: when you expect rationed love, you unconsciously arrange it — choosing the guarded ones, guarding yourself with the open ones. The repair is internal first: **stop pre-agreeing to scarcity**. Practice warmth without waiting for it to be safe; name the distance out loud instead of matching it. Duty and tenderness are not opposites — the mature form of this aspect is **devotion: love that stays, and also melts**." },
  "moon-uranus-conjunction": { title: "Moon conjunct Uranus", body: "Your inner weather changes fast and without apology. You can wake up a slightly different person than the one who went to sleep, and you need freedom the way others need routine — **closeness works best for you with the window open**. Conventional scripts for home and family may have never fit; you likely found or built belonging in unconventional shapes, and those shapes were not compromises. They were accuracy.\n\nThe practice is **honoring the need for space out loud** — before the trapped feeling makes the announcement for you. Tell the people you love: my distance is regulation, not rejection. Intimacy that includes your orbit stops feeling like a trap and starts feeling like home. Your changeability is not instability. It is **aliveness with a fast refresh rate**, and the right people find it thrilling." },
  "moon-uranus-square": { title: "Moon square Uranus", body: "Just as you settle into feeling safe, something in you pulls the fire alarm. The cozy evening suddenly itches; the secure bond triggers an urge to test it; comfort and confinement arrive **wearing the same coat**, and your nervous system cannot always tell them apart. This grind between the need to belong and the need to bolt is old, and it is not a character flaw.\n\nThe growth is learning that **steadiness and freedom are not enemies** — you can be held loosely. Build the escape valves into your commitments on purpose: solo time, separate rooms, renegotiable terms. When space is guaranteed, the alarm stops ringing. What this square is ultimately making is rare: someone who chooses closeness **freshly, repeatedly, freely** — which is worth more than closeness by default." },
  "moon-uranus-opposition": { title: "Moon opposite Uranus", body: "The people closest to you keep changing the terms — or you do, right when things get comfortable. Sudden distance, abrupt reversals, the partner who needs space the week you finally relaxed: disruption in your intimate life is the recurring weather. Look underneath and you will usually find **an unmet need for breathing room** that nobody in the arrangement has named, so it detonates instead.\n\nThe repair is structural: **build the space in deliberately** so nobody has to explode to get it. Separate hobbies, honest check-ins, permission to evolve without it meaning goodbye. Choose people who can love a changing person — and be one who can. Handled this way, the electricity stops being an exit strategy and becomes what it wanted to be: **aliveness inside the bond, not instead of it**." },
  "moon-neptune-conjunction": { title: "Moon conjunct Neptune", body: "You feel the room before you enter it. Your emotional body is porous — tuned to undercurrents, dreams, and the unsaid — which makes you a natural healer, artist, or confessor, and also **an easy sponge** for weather that was never yours. You have probably carried moods home from strangers. Sometimes you cry and cannot say whose grief it is.\n\nThe gift is real and it needs a container. Salt water, art, sleep, and honest boundaries keep sensitivity from becoming damage: **discharge what you absorb** the way musicians case their instruments. Practice the sorting question — is this mine? — and believe the answer. Your permeability is not weakness; it is rare instrumentation. Protected properly, it lets you offer the thing this world is starved for: **being truly, wordlessly understood**." },
  "moon-neptune-square": { title: "Moon square Neptune", body: "Your feelings and your fantasies blur, so you sometimes mourn things that never quite happened and long for homes that never quite existed. Nostalgia arrives for places you have not been; a real relationship gets measured against an imagined one and quietly loses. The fog is genuine — **your inner life is more vivid than most people's outer one** — and it can leave you seasick about what you actually feel.\n\nThe friction is teaching **discernment, not cynicism**. Practice reality-testing your emotional weather: name three concrete facts when the longing swells, ask a trusted friend what they see, keep a record you can reread. Reality, met clearly, turns out to be a better container for your tenderness than any mirage — because it can actually hold you. **The dream was pointing at something buildable all along.**" },
  "moon-neptune-opposition": { title: "Moon opposite Neptune", body: "You idealize the people you need, then feel abandoned by the humans they turn out to be. The rescuer, the soulmate, the one who finally understands — each arrives haloed, and each eventually does something unmistakably mortal. The dream keeps living **on the far side of the relationship**, always in the other person, always slightly out of reach.\n\nBalance comes when compassion flows both ways: toward them as they are, and **toward you as you are** — including the part that needed the halo, because reality once disappointed it badly. Practice loving at actual size. Ask who this person is, not who they could become in the movie. The intimacy available with a real, flawed, present human is quieter than the fantasy and **infinitely more nourishing** — it can actually feed you." },
  "moon-pluto-conjunction": { title: "Moon conjunct Pluto", body: "You feel in fathoms. Emotional attachments run all the way down, and you sense **the hidden machinery in every family, every room** — who holds the power, what is not being said, where the bodies are buried. As a child this probably made you the one who knew too much. That depth once felt like too-muchness; it is actually your power source.\n\nThe initiation is **trusting someone with the bottom layer** — letting one person see the intensity you have learned to dose out carefully. Watch the survival reflexes: testing loyalty, withholding to stay safe, loving with one hand on the exit. You do not have to manage people to keep them. Real bond, for you, is transformation — and the ones who can meet your depth will not drown in it. **Choose those.**" },
  "moon-pluto-square": { title: "Moon square Pluto", body: "Your needs carry an old survival charge, so closeness can trigger control — jealousy, testing, the urge to grip what you fear losing. Somewhere early, love and danger got filed in the same drawer, and your nervous system still cross-references them. The grind is real: intimacy sets off alarms that have nothing to do with the person in front of you.\n\nAnd so is the payoff: **every fear you name out loud loses its grip**. Say the raw thing — I am scared you will leave — instead of running the covert test. Therapy, deep friendship, and time do honest work here. What this square builds, worked consciously, is a heart with **fathoms and a working rudder**: someone whose love is intense because it is real, not because it is frightened. **That love transforms people.**" },
  "moon-pluto-opposition": { title: "Moon opposite Pluto", body: "Intimacy comes with power weather: someone always seems to hold the emotional leverage, and you have played both roles — the one who grips and the one who withholds, sometimes in the same year. Bonds feel fated, consuming, impossible to be casual about. Underneath the intensity is **a hunger for unconditional bond** that got tangled with fear before you had words for either.\n\nThe untangling is the work of your life, and it is doable: name the fear before it becomes strategy, choose people who do not require you to shrink or to grovel, notice when you are testing instead of trusting. Untangled, your depth stops being a battleground and becomes the gift it always was — **loyalty like bedrock**, love that holds because it chooses to, **a grip become an embrace**." },
  "mercury-venus-conjunction": { title: "Mercury conjunct Venus", body: "You think in aesthetics and speak in silk. Words, for you, are **a form of touch** — you can make almost any idea sound like an invitation, and people often say yes to you before they have fully parsed the sentence. Your letters get kept. Your compliments get remembered for years. Diplomacy is not a technique you learned; it is the shape your mind naturally makes.\n\nThe refinement to watch: keeping your speech beautiful **without sanding off the true, unlovely parts**. Grace that avoids hard truths curdles into evasion, and you are too gifted for that. Practice delivering the difficult sentence in your own warm voice — it turns out kindness and candor share a grammar. When beauty and honesty travel together in your mouth, **people trust you with everything**." },
  "mercury-venus-square": { title: "Mercury square Venus", body: "What you think and what will keep the peace are often two different sentences, and you feel the grind every time you choose. You have swallowed opinions to preserve an evening; you have polished a truth until it no longer resembled itself. **Diplomacy is your gift; self-censorship is its shadow** — and the line between them moves daily.\n\nThe practice is saying the honest thing warmly: not softening the content, just the delivery. Notice that the relationships you value most are the ones that survived your real opinion. Each time you choose candor with care, the square converts a little more friction into **eloquence with a backbone**. The peace you keep by silencing yourself was never peace — it was postponement. **Your true voice, kindly used, is the harmony.**" },
  "mercury-venus-opposition": { title: "Mercury opposite Venus", body: "You toggle between the analyst and the charmer, and other people often get cast as whichever one you are not currently being — the cold logician to your warmth, the flatterer to your rigor. Conversations become quiet negotiations between **truth and harmony**, and you can feel yourself choosing a side mid-sentence, wondering which version of you the room can hold.\n\nThe sweet spot is real and it is yours to claim: **candor delivered with genuine affection** persuades better than either alone. Stop outsourcing one half — be the person who says the accurate thing and means the kindness in it. In close relationships, watch the pattern where one of you is assigned honesty and the other charm. Trade roles on purpose. **Integration here sounds like love that tells the truth.**" },
  "mercury-mars-conjunction": { title: "Mercury conjunct Mars", body: "Your mind is a blade and you keep it sharp. Thought converts to speech converts to action with almost no lag, which makes you **decisive, funny, and formidable in a debate** — you find the weak point in an argument the way water finds a crack. People learn quickly not to waste your time, and your directness is a kind of respect: you say it to their face or not at all.\n\nThe craft is aim. **A blade this quick can cut before you have decided to**, and sarcasm is your particular temptation — wit weaponized at whoever is nearest. Point the sharpness at problems, not people, and you become invaluable: the one who says what everyone was circling, the mind that cuts through committee fog. **Precision in service of something is power; precision for its own sake is just injury.**" },
  "mercury-mars-square": { title: "Mercury square Mars", body: "Words leave you faster than your judgment can chase them, and the aftermath has taught you plenty — the sent message you would pay to unsend, the sharp reply that won the point and lost the room. This grind between thinking and striking is real friction, and it is also **the exact training ground for communicators with genuine force**.\n\nThe mastery lives in the pause before you send it. Not suppression — **timing**. Draft the hot response, then let it cool overnight; you will usually keep the strength and lose the shrapnel. Debate recreationally so your combativeness has a gym. Over years, this square builds something rare: a voice with **both edge and aim**, heat that arrives exactly when and where it is useful. The people who mocked your bluntness will someday hire it." },
  "mercury-mars-opposition": { title: "Mercury opposite Mars", body: "You attract debaters, interrupters, and people who argue with your facts on principle. Conversations turn adversarial around you with suspicious regularity, and it rarely feels like your doing — yet there you are again, defending a position you did not know you held that fiercely. The sparring partners are mirrors: they carry **a combative sharpness you have not fully claimed** as your own.\n\nThey are also sharpening you, though it seldom feels like a favor. The balance is learning to **hold your position without needing to win** — stating your case once, clearly, and letting it stand unguarded. Paradoxically, that is when you start winning: arguments de-escalate when you stop feeding them your defensiveness. Own your edge directly and the ambient hostility thins. **What remains is honest debate — the kind that improves both minds.**" },
  "mercury-jupiter-conjunction": { title: "Mercury conjunct Jupiter", body: "Your mind thinks in panoramas. You connect dots across disciplines, tell stories that make small facts feel mythic, and **teach almost by accident** — people leave conversations with you carrying more world than they arrived with. Meaning is your native subject: you cannot report an event without also finding what it signifies, and your optimism about ideas is itself an education.\n\nThe craft to develop is **compression**. A vision this big lands hardest when you can say it in one clean sentence, and your tendency is fifteen. Practice the ruthless edit; treat brevity as a gift to the listener, not a loss to the idea. And check the details before you publish the panorama — enthusiasm has occasionally done your fact-checking. Disciplined, this mind becomes what it was built to be: **wisdom that travels**." },
  "mercury-jupiter-square": { title: "Mercury square Jupiter", body: "Your ideas arrive at billboard scale, and the details grind against the grandeur. You may promise in paragraphs what you can deliver in sentences — the course outlined before the first lesson is written, the theory announced before the data is in. The gap between vision and execution can make you doubt the vision. **Do not. The vision is the engine; it just needs an editor.**\n\nThis friction is an education in scoping: cut the plan in half, then start. Finish one small true thing before announcing the next large one. Beware intellectual overconfidence — the moment you feel certain is exactly when to check a source. Once you learn the edit, your natural breadth becomes trustworthy, and people stop smiling politely at your ideas and start **funding them**." },
  "mercury-jupiter-opposition": { title: "Mercury opposite Jupiter", body: "You bounce between the fine print and the philosophy, and other people tend to hold whichever end you have dropped — the pedant who nitpicks your vision, the dreamer who floats above your facts. Debates about meaning follow you around; you keep meeting people whose beliefs seem either too small or too unmoored, and the irritation is **information about your own unintegrated halves**.\n\nIntegration looks like this: beliefs sturdy enough to survive your own fact-checking, and facts arranged into actual meaning. Practice arguing both sides of your own convictions; read the sources of people you disagree with until you can state their case fairly. What this opposition builds, matured, is rare and needed — **a mind both rigorous and large**, capable of holding detail and horizon in the same steady gaze." },
  "mercury-saturn-conjunction": { title: "Mercury conjunct Saturn", body: "You think in load-bearing sentences. Your mind builds slowly and permanently, distrusting shortcuts, and what you finally say **tends to hold** — people quote you back to yourself years later. In school this may have felt like deficiency: the fast talkers glittered while you were still constructing. But your answers outlasted theirs, and somewhere along the way you noticed.\n\nThe early shadow was believing slow meant stupid. It never did. **Depth is your dialect**; let the skimmers skim. The practice now is publishing before you feel ready — your internal standard runs about twenty percent past what excellence actually requires, and the world needs your carefully built thoughts more than it needs them perfect. Speak. The silence you keep out of rigor reads, from outside, like absence. **Your voice is architecture; build in public.**" },
  "mercury-saturn-square": { title: "Mercury square Saturn", body: "An internal editor reviews your words before, during, and after you speak, and the grind can make expression feel like a permanent exam. You rehearse the email, re-read the sent message, replay the meeting at 2 a.m. The exhaustion is real — and so is what the friction is building: **rigor, precision, a voice people trust precisely because it is careful**.\n\nHere is the reframe that changes everything: the editor works for you now, not the other way around. Use it for the second draft, never the first — let the raw words land on the page before the review begins. Speak in rooms where the stakes are low until your voice remembers it is allowed. Your thinking is sounder than your doubt reports. **Publish before you feel ready; the readiness follows the publishing.**" },
  "mercury-saturn-opposition": { title: "Mercury opposite Saturn", body: "You keep meeting the skeptic: the teacher who doubted you, the colleague who demands citations, the silence after you share an idea that lands like a gavel. External judgment mirrors **an inner verdict still under appeal** — some old authority pronounced your thinking insufficient, and you have been re-arguing the case ever since, often with people cast unknowingly in the original role.\n\nThe repair is retiring the appeal. Your ideas do not need the skeptic's signature to be sound; they need testing, which you already do more honestly than most. Practice stating a conclusion without the apologetic preamble. Seek out mentors who critique to build, not to gatekeep — you bloom under rigorous kindness. Matured, this opposition yields the best kind of mind: **one that has earned its own trust**, and speaks like it." },
  "mercury-uranus-conjunction": { title: "Mercury conjunct Uranus", body: "Your mind moves in lightning strikes, arriving at conclusions by routes you cannot always retrace. You see the pattern **three steps before the room does**, and the gap between your insight and their catching up has been a lifelong social puzzle — you have learned to wait, badly, while the obvious becomes obvious to everyone else. Boredom is your kryptonite; novelty is your oxygen.\n\nThe craft is **translation**: building bridges back to slower thinkers so your insights land instead of just startling. Show your work even when you skipped the steps; date your predictions so the record can vindicate you kindly. And protect the strangeness — do not sand your mind down to be legible. The world catches up to minds like yours eventually. **Your job is making sure the transmission survives the wait.**" },
  "mercury-uranus-square": { title: "Mercury square Uranus", body: "Your best ideas interrupt you — mid-sentence, mid-shower, mid-someone-else's-story — and you interrupt everyone else. This square grinds between brilliance and coherence: insight scattered across half-finished notebooks, seventeen open tabs, the genius thought lost because nothing caught it. The static is real, and so is the signal underneath it.\n\nHere is the counterintuitive truth: **structure is not the enemy of your originality; it is the amplifier**. A capture system — one notebook, one inbox, one ritual for reviewing the sparks — turns your electrical storms into a body of work. Finish one idea per season all the way to done; completion is your radical act. The world has plenty of scattered brilliance. What it lacks is **lightning that learned to strike the same place twice** — and that discipline is available to you." },
  "mercury-uranus-opposition": { title: "Mercury opposite Uranus", body: "Contrarians and wildcards populate your conversations, saying the destabilizing thing you were half-thinking anyway. You watch someone else voice the radical idea and feel a jolt that is equal parts objection and recognition. The pattern is worth naming: you have been **outsourcing your own unconventional mind**, then arguing with it in other people's mouths.\n\nClaim the strange thoughts as yours. Say the heterodox thing in your own voice, at your own timing, with your own reasoning attached — and notice how the ambient chaos quiets when nobody has to shock you into your own opinions. The mature form of this opposition is a mind in **genuine dialogue with difference**: you seek out the perspectives that rearrange you, on purpose, and return the favor. **Disruption becomes exchange. Exchange becomes growth.**" },
  "mercury-neptune-conjunction": { title: "Mercury conjunct Neptune", body: "You think in images, atmospheres, and tides, and ordinary language sometimes feels too small for what you perceive. Poetry, music, and metaphor are **your native grammar** — you understand things sideways, through resonance, and your best explanations sound like weather reports from a country only you have visited. People come to you when they cannot say what they mean; somehow you can.\n\nThe practice is **precision on demand**: keeping one foot in the literal so the visions can be delivered. Learn the boring skills — dates, numbers, exact quotes — as an act of devotion to your gift, because an uncredentialed mystic gets dismissed and a precise one gets believed. Write daily; the channel needs a container or it floods. **Your imagination is a real instrument. Tune it, and it will carry truths that argument never could.**" },
  "mercury-neptune-square": { title: "Mercury square Neptune", body: "Facts blur at the edges for you, and communication can slide into fog — yours or other people's. You remember the feeling of the conversation but not the terms agreed; you explain something clearly in your head and watch it dissolve on contact with air. Misunderstandings follow you like weather, and you have been called both dreamy and evasive when you were neither. **The channel is strong; the tuning drifts.**\n\nThe grind teaches verification as self-respect: write things down, confirm the details, ask the clarifying question even when it feels unpoetic. Beware the small fibs of convenience — this aspect punishes them with compound interest. Disciplined, your imagination becomes a trustworthy instrument: the one who can **describe the invisible accurately**, which is a skill civilizations quietly run on." },
  "mercury-neptune-opposition": { title: "Mercury opposite Neptune", body: "You attract dreamers, mystics, and the occasional beautiful liar — people whose words shimmer more than they hold. You have believed things because they were gorgeous; you have also been the skeptic drowning someone else's vision in questions. The oscillation is the tell: **imagination and rigor are both yours**, and you keep assigning one of them to whoever is standing opposite.\n\nBalance arrives when you let your own thinking be both visionary and checked. Practice the double read: first with wonder, then with a pencil. When someone's story enchants you, honor the enchantment and verify the facts — the two are not enemies. What this opposition builds at maturity is a rare discernment: **you can hear the true note inside the beautiful noise**, and you stop paying full price for shimmer." },
  "mercury-pluto-conjunction": { title: "Mercury conjunct Pluto", body: "Your mind is an excavation site. You do not have light conversations so much as **strategic descents** — within minutes you are past the weather and into the wound, and you can read subtext like large print. Secrets find you; people confess to you unprompted, sensing you already half-knew. Words from you carry disproportionate weight, and you have watched a single sentence of yours rearrange someone's year.\n\nThat is power, and power needs ethics. Use the penetration to **liberate truth, not to hold it over people** — the difference between a surgeon and someone with a knife is consent and intention. Give the intensity honest work: research, psychology, investigation, the writing that says what no one else will. And let some conversations stay shallow. **Not every pond needs dredging; some are for floating.**" },
  "mercury-pluto-square": { title: "Mercury square Pluto", body: "Your thoughts can turn obsessive, circling one subject like water around a drain — the conversation replayed forty times, the suspicion that builds its own case file, the research spiral at 3 a.m. Conversations sometimes tip into interrogations without your noticing; you just wanted the truth, and the room wanted lunch. **The depth is a gift; the compulsion is the tax.**\n\nThe friction is teaching mental sovereignty: you choose the descent instead of being dragged. Give the intensity a professional container — research, analysis, therapy, deep study — and it becomes formidable rather than corrosive. Learn your early warning signs of the spiral and interrupt it with the body: walk, lift, breathe. Matured, this square produces **a mind that goes where others cannot and comes back with the truth** — on purpose, with a return ticket." },
  "mercury-pluto-opposition": { title: "Mercury opposite Pluto", body: "You keep encountering people who probe, persuade, or pull your thinking somewhere darker — and part of you is fascinated. The manipulator you saw through too late, the intense friend who knows exactly what to say, the debate that felt like psychological chess. These figures reflect **your own unclaimed investigator**: a penetrating intelligence you sensed early was too much, and quietly handed to others.\n\nTake it back. When you own the depth of your own perception, manipulation loses its foothold — you cannot be easily played by dynamics you can name. Practice saying what you notice, tactfully but out loud; your radar is better than you admit. What replaces the chess games is the real prize: **dialogue with actual power in it**, conversations that transform both people because **nobody is hiding the depth anymore**." },
  "venus-mars-conjunction": { title: "Venus conjunct Mars", body: "Desire and affection are fused in you, so you pursue what you love with unusual directness — there is no coy waiting period between noticing and wanting, and people feel the charge when you enter a room. Attraction, creativity, and appetite all run on **one live current**. Whatever your style or presentation, you carry a magnetism that does not ask permission, and your enthusiasm for people, beauty, and pleasure is frankly contagious.\n\nThe refinement is **pacing**: wanting wholeheartedly without overwhelming, and letting some attractions season before you act on them. Not every spark is an assignment. Practice savoring the wanting itself — desire held, not just discharged, becomes creative fuel for art, work, and long love. **Your heat is a gift; tempo is what makes it music.**" },
  "venus-mars-square": { title: "Venus square Mars", body: "What you want and what you love keep grinding against each other: passion arrives with friction built in. Your relationships run hot — creative, magnetic, occasionally combative — and you may notice a pattern where desire spikes during conflict and softness feels strangely riskier than fighting. **Tenderness and hunger are not yet convinced they can share a bed**, and the negotiation shows.\n\nThe growth is learning that they can: the best intimacy holds both at once, and yours especially. Practice staying soft while wanting fiercely; practice wanting out loud while staying kind. Channel the surplus charge into making things — this square is one of astrology's great artistic engines. When the war between affection and desire ends, what remains is remarkable: **love with a pulse**, passion that protects what it wants." },
  "venus-mars-opposition": { title: "Venus opposite Mars", body: "Attraction, for you, tends to spark across difference: pursuer and pursued, fire and grace, forever trading places. The chemistry is real and so is the tug-of-war — you may notice relationships polarizing into roles, one person always initiating while the other always receives, until resentment quietly files a complaint. **The roles are costumes, and you both own the full wardrobe.**\n\nBalance comes when you stop assigning the parts: let both of you want and be wanted, chase and be caught, soften and assert. Practice switching — initiate if you usually wait; receive if you usually drive. The voltage does not drop when the roles unfix; it doubles, because **two whole people generate more heat than two halves**. That is the integration this opposition is patiently arranging." },
  "venus-jupiter-conjunction": { title: "Venus conjunct Jupiter", body: "You love largely. The two benefics fused make you generous with affection, drawn to beauty at scale, and gifted at making people feel **celebrated rather than merely liked**. Pleasure trusts you; delight is your first language. You throw the gathering people remember, give the gift that lands, and believe in your people so visibly that they start believing in themselves.\n\nThe only shadow is excess — promising more heart than any calendar can hold, loving so widely that depth gets rationed thin. **Loving fewer things more deeply is your version of discipline.** Practice the devoted narrow: three people fully rather than thirty warmly, one beautiful thing finished rather than five begun. Your abundance is real and renewable; aimed, it becomes what it was always meant to be — **a blessing with follow-through**." },
  "venus-jupiter-square": { title: "Venus square Jupiter", body: "Your appetite for pleasure, romance, and the finer things outpaces your logistics, and the grind shows up in overspent budgets, overbooked weekends, and affection promised in quantities no schedule can honor. More is your reflex: more beauty, more people, more of whatever felt good last time. **Nothing here needs shrinking — only sequencing.**\n\nThe friction is teaching your generosity to keep its promises. Practice the delayed yes: want it, wait a week, then decide. Notice when pleasure has stopped pleasing and become momentum. In love, watch the pattern of grand beginnings that outrun their foundations — pour the same extravagance into the middle of relationships, where it is rarer and worth more. Sequenced, your abundance becomes legendary instead of exhausting: **the friend whose yes means yes, lavishly**." },
  "venus-jupiter-opposition": { title: "Venus opposite Jupiter", body: "You are torn between the intimate and the expansive: the person in front of you and the possibility over there. Partners can feel like either anchors or launching pads, and you may cycle between craving cozy devotion and feeling caged by it — **the love you have and the life you imagine keep bidding against each other**.\n\nThe balance is a love spacious enough to grow inside, so leaving stops looking like the only adventure. Choose people who want to become alongside you; build relationships with built-in horizons — travel, study, reinvention, shared risk. And bring your appetite home: the grand romance you keep locating elsewhere is a quality of attention, portable and learnable. **When the relationship itself becomes the expedition, both hungers finally eat at the same table.**" },
  "venus-saturn-conjunction": { title: "Venus conjunct Saturn", body: "You treat love as a serious craft: slow to open, deliberate in commitment, **unshakably loyal once you are in**. Early on, affection may have felt earned rather than given — warmth with terms, tenderness on a schedule — and you learned to expect the invoice. So you built a love style with excellent structural integrity and a slightly guarded front door.\n\nThe healing is **receiving freely**: letting affection arrive without auditing it for hidden costs, letting someone adore you before you have finished proving deserving. Practice accepting the compliment whole. Your love ages like something built to last because it is — while faster hearts burn through beginnings, you are quietly mastering middles and ends. **Late-blooming is still blooming**, and yours tends to be spectacular." },
  "venus-saturn-square": { title: "Venus square Saturn", body: "A quiet ledger runs under your relationships, tallying worth, doubting welcome — the reflexive suspicion that love must be earned, maintained, and could be repossessed for insufficient payments. The grind between wanting closeness and bracing against it built your depth and your reserve; people sense there is more in you than you release, and they are right.\n\nHere is the work, and it is gentle: **every time you let affection in without negotiating for it, the ledger loses a page**. Accept the kindness without immediately reciprocating. Say the loving thing before it is safe. Notice that the people who stay were never keeping your accounts — the auditor was internal, and it is aging out of a job. What this square builds, worked patiently, is **love with real foundations**: tested, chosen, and finally, received." },
  "venus-saturn-opposition": { title: "Venus opposite Saturn", body: "You keep meeting love with conditions attached: distance, duty, timing, someone's walls. The unavailable one, the age gap, the relationship that ran on obligation, the partner whose affection required an application. The pattern feels external — bad luck in a long coat — but it mirrors **an internal question about whether you are worth the trouble**.\n\nYou are. Answer it inside and the relationships stop administering the test. Practice warmth without pre-clearing it for rejection; choose the available person even though availability feels suspiciously easy; let duty and delight coexist instead of taking turns. Saturn across from Venus matures into the good thing: **devotion — love that shows up, keeps its word, and stays soft anyway**. That is not the consolation prize. **It is the whole prize.**" },
  "venus-uranus-conjunction": { title: "Venus conjunct Uranus", body: "Your heart is an original. You love suddenly, unconventionally, and on your own terms — allergic to scripts about how romance is supposed to look, whom it should include, or what shape a committed life must take. **Freedom is a love language for you**, and some of your truest bonds may have forms that confuse onlookers and fit you perfectly. Their confusion is not your problem.\n\nThe craft is building bonds that stay interesting, so novelty stops requiring departure. Choose people who keep becoming; write agreements you can renegotiate; let the relationship be a laboratory rather than a museum. Your difference here is **inheritance, not defect** — you descend from everyone who ever loved outside the lines and made it beautiful. Keep making it beautiful. **The scripts were never load-bearing anyway.**" },
  "venus-uranus-square": { title: "Venus square Uranus", body: "Closeness and freedom grind against each other in your heart: the moment love settles, something in you itches for the open road. You have likely ended good things because they got comfortable, or stayed and felt a low hum of captivity that had nothing to do with your partner's behavior. **This is not brokenness — it is an unmet need for space inside intimacy**, announcing itself the only way it knows.\n\nName it early and your relationships stop having to break to breathe. Build the freedom in structurally: separate interests, solo trips, terms revisited annually like the living contract love actually is. Choose partners who find your changes interesting rather than threatening. Done consciously, this square delivers its rare gift — **a love that is chosen fresh, over and over**, because it was never a cage to begin with." },
  "venus-uranus-opposition": { title: "Venus opposite Uranus", body: "You draw electric, unpredictable partners — or become one — whenever a relationship gets too settled. The pattern: stability arrives, then the lightning bolt, the sudden distance, the person who reroutes everything. It can look like a curse of chaotic taste. It is closer to **a disowned need for independence within love**, hiring other people to act it out.\n\nClaim the need directly and the casting call closes. Say plainly: I require room, evolution, the right to keep surprising you — and offer the same. Choose relationships with space built into the architecture rather than smuggled in through crisis. When you stop treating your own freedom as contraband, the lightning changes jobs: **it stops being the exit strategy and becomes the chemistry** — aliveness that keeps a long love awake." },
  "venus-neptune-conjunction": { title: "Venus conjunct Neptune", body: "You love the way tides love the shore: totally, and with **a longing that outreaches any single person**. Romance, art, and devotion blur together in you — falling in love feels like religion, music can wreck you, and you have adored people partly for the beauty you could see through them. Venus here is exalted in the direction of the infinite: your heart genuinely touches something most people only read about.\n\nThe practice is loving the actual human, not the shimmer — and letting your boundless heart keep a boundary or two. Check in: am I in love with this person or with the light I have projected onto them? Both can be true; only one can hold you back. Give the oceanic longing its proper objects — art, practice, the sacred — and **the humans in your life can finally be loved at human scale, which is where love actually lives**." },
  "venus-neptune-square": { title: "Venus square Neptune", body: "You fall for potential — for almosts, for the person someone could be with enough of your faith applied — and the grind comes when reality files its report. The pattern has a shape: enchantment, devotion, slow-dawning discrepancy, heartbreak that feels like waking. You may also blur yourself in love, becoming whatever the beloved seems to want. **The romanticism is not the flaw; the unchecked projection is.**\n\nThis square is refining your radar, not punishing your heart. Practice loving what is actually there: date the evidence, not the trailer. Keep your friends' eyes handy in the early enchantment. And hold onto yourself — the shape-shifting costs you the very intimacy it tries to buy. Loving what is real, as it is, turns out to be **the deeper enchantment**: it can love you back." },
  "venus-neptune-opposition": { title: "Venus opposite Neptune", body: "Partners arrive haloed, then human, and the descent can feel like betrayal when it is actually just **focus** — the lens finding true after the soft-glow opening. You keep meeting the dream in other people: the muse, the wounded artist, the almost-saint, each carrying a radiance that was yours on loan. When they turn out to be mortal, the grief is real, but it is grieving the projection, not the person.\n\nYou are learning to see love clearly without loving less — which is the advanced course. Practice admiration with accuracy: praise what they actually do, not what you dreamed they might. And bring the projected devotion home: make the art, keep the practice, live the beauty you keep subcontracting. **The shimmer was never in them. It travels with you.**" },
  "venus-pluto-conjunction": { title: "Venus conjunct Pluto", body: "You love at depth or not at all. Attraction, for you, is transformation — **every real bond rearranges you**, and surface connection reads as static. You bond soul-first, notice everything, and carry an intensity that people feel as either irresistible or alarming, sometimes both in the same evening. Casual was never going to be your genre, and pretending otherwise has only ever cost you.\n\nThe work is choosing people who can meet the deep end **without drowning or fleeing** — and watching your own grip when fear rises. Intensity can shade into possession when the old wound whispers that everything beloved gets taken. It does not. Practice loving with open hands; let the bond prove itself through freedom rather than surveillance. Held that way, your depth is not too much. **It is the whole point of you.**" },
  "venus-pluto-square": { title: "Venus square Pluto", body: "Love and power got wired together somewhere early, so intimacy can trigger possession, testing, or the fear of being consumed — the jealousy that ambushes you, the loyalty tests you run without announcing them, the way closeness and threat arrive in the same body. The grind is fierce: you want union completely and trust it barely. **Both of those are old, and neither is your fault.**\n\nHere is the reward structure: each time you choose trust over control, your capacity for real union expands — measurably, permanently. Name the fear instead of strategizing around it: I am afraid of losing you disarms what surveillance never could. Do the depth work; this square repays therapy like a high-yield account. What it is building is formidable — **love with fathoms and clean hands**, intensity that transforms instead of grips." },
  "venus-pluto-opposition": { title: "Venus opposite Pluto", body: "Your relationships carry undertow: obsessive attractions, power trades, the lover who transforms you or the one you cannot release. Bonds arrive feeling fated and depart feeling seismic; somewhere in the middle, questions of control — who holds it, who fears losing it — run beneath even your gentlest connections. **What pulls at you from others is your own buried intensity asking to be owned.**\n\nOwned, it becomes depth: you bring the full charge to the relationship instead of meeting it as weather. Projected, it becomes drama on a loop. The practice is radical honesty about your own wanting — admit the hunger, the jealousy, the power you actually have, out loud, to someone safe. Intensity confessed loses its undertow. What remains is the real gift: **love strong enough to transform both people, with nobody swept away**." },
  "mars-jupiter-conjunction": { title: "Mars conjunct Jupiter", body: "Your drive comes with a philosophy attached: you do not just act, you **crusade**. Effort feels meaningful to you or it feels pointless — there is no neutral gear — and when you believe in what you are doing, your momentum is enormous and genuinely contagious. People rally behind your certainty; you make courage look like common sense. Wins tend to come big for you because you swing big, on principle.\n\nThe tending is **proportion**: making sure the mission deserves the horsepower before you commit the engine. Not every hill is the hill, and righteousness can outrun accuracy when the blood is up. Ask one trusted skeptic to audit your crusades. Aimed at something worthy, this fusion is a life force multiplier — **conviction that moves, and moves others**." },
  "mars-jupiter-square": { title: "Mars square Jupiter", body: "You bet big and swing early, and the grind between appetite and follow-through has taught you some expensive lessons — the project three sizes too large, the risk that looked like faith and turned out to be math you skipped. The failures were tuition, not verdicts. **Boldness is your raw material; scoping is the skill being installed.**\n\nKeep the boldness; add the math. Before the next leap, do the unglamorous audit: what does this actually require, and do I have it, and if not, where does it come from? Your enthusiasm is the rarest kind of fuel — most people cannot manufacture it at any price. When it learns to size the jump before jumping, this square becomes **an engine very few can match**: audacity with a flight plan." },
  "mars-jupiter-opposition": { title: "Mars opposite Jupiter", body: "You oscillate between charging ahead and questioning the point — between the sprint and the meaning of the race. Some seasons you act relentlessly and wonder why; others you philosophize endlessly and act barely. Other people often hold your missing pole: the reckless friend who pushes you toward risks, the cautious one who preaches you back from them, each carrying **a conviction you have not yet integrated**.\n\nThe balance is **ambition with a philosophy**: knowing why you run before you enter the race, and then actually running. Practice writing the reason before starting the effort — one sentence of why per project. Effort without meaning burns you out; meaning without effort curdles into commentary. Fused, they make you formidable: **a person whose actions argue their beliefs**, persuasively, in public, for the long haul." },
  "mars-saturn-conjunction": { title: "Mars conjunct Saturn", body: "Your drive runs through a governor: full throttle and firm brake, engineered into the same machine. Early on that felt like pure frustration — wanting fiercely and being slowed, ambition arriving with a headwind attached. Over time it becomes **precision**: you waste almost no motion, and what you commit to actually finishes, which puts you in a small minority of humans.\n\nYou are built for **the long campaign** — the discipline that outlasts everyone who started faster and flamed out sooner. Honor the design: choose fewer goals and pursue them for years; your compounding beats their sprinting every time. And watch the internalized brake that fires from fear rather than wisdom — sometimes the hesitation is just old frustration wearing a safety vest. **Test the brakes; trust the engine.**" },
  "mars-saturn-square": { title: "Mars square Saturn", body: "Every push meets a wall, and you have come to expect the resistance before you even begin — the delayed permission, the blocked path, the effort that costs double what it costs others. The exhaustion is legitimate. And here is the reframe that changes the story: **the wall is a training apparatus**. This square builds strength through opposition, rep by rep, year by year.\n\nThe endurance you are developing cannot be bought, borrowed, or faked — and the people who cruised past you early tend to stall exactly where your conditioning begins. The practice is pacing without quitting: rest as strategy, not surrender. And check which walls are real; some are old defeats projected forward. **Push where it matters, rest on schedule, and let the compounding do what it has always been doing: making you unstoppable slowly.**" },
  "mars-saturn-opposition": { title: "Mars opposite Saturn", body: "Your momentum keeps meeting other people's rules: the boss who blocks, the system that stalls, the gatekeeper who says not yet. Authority and your will have circled each other your whole life, and the standoffs can feel personal — as if the world assigned you extra friction. Some of those limits are real and worth respecting. **Some are your own hesitation wearing a uniform.**\n\nLearning which is which sets your engine free. Practice the sorting question: is this obstacle a fact, a negotiation, or a fear? Facts get worked around, negotiations get entered, fears get named and retired. Notice, too, when you become the brake on someone else's drive — the poles trade places. Matured, this opposition yields **disciplined force**: power that can wait, push that knows its timing, and **authority earned rather than fought**." },
  "mars-uranus-conjunction": { title: "Mars conjunct Uranus", body: "Your actions carry voltage: sudden, original, and impossible to predict — including for you. You break stalemates just by entering the room, do the unthinkable thing while committees are still forming, and your body seems wired with a **strike-first relationship to the future**. Routine physical life bores you into mischief; you need movement with novelty in it, risk with intelligence in it.\n\nThe mastery is timing your lightning: **choosing when to strike** rather than discharging at whatever is nearest when the charge builds. Build pressure-release into your weeks — sprints, climbs, cold water, anything sudden and safe — so the voltage has scheduled exits. Before the irreversible move, one breath: is this liberation or just detonation? Liberation, always. You were built to free things, **starting with yourself, repeatedly**." },
  "mars-uranus-square": { title: "Mars square Uranus", body: "Restlessness builds in you like static until something snaps into action — the abrupt quit, the sudden move, the sharp turn nobody saw coming, including you. The results are brilliant or breakage, often both in the same gesture. Nothing is wrong with your wiring; **the charge is real and it needs a schedule**, not a suppression order.\n\nThe grind is teaching deliberate release. Give the voltage regular, chosen work: hard exercise, invention, deadlines with adrenaline in them, change enacted in planned increments rather than eruptions. Learn your pre-snap signals — irritability, boredom sharpening into contempt — and act early, smaller. The mature form of this square is genuinely rare: **decisive originality on demand**, the person who moves suddenly and correctly because the suddenness finally has a steering wheel." },
  "mars-uranus-opposition": { title: "Mars opposite Uranus", body: "Sudden conflict and abrupt reversals seem to come at you from outside: the erratic rival, the plan upended at the last minute, the person whose unpredictability keeps detonating your calendar. The chaos looks external and keeps choosing you — which is the clue. **It mirrors an impulsiveness you have not fully owned**, exiled to other people's behavior where it can ambush you freely.\n\nClaim your own wild card and the ambushes largely stop. Make the surprising move yourself, deliberately, before circumstances force a worse version of it. Build slack into your plans so disruption has somewhere to land. And when the erratic ones appear, hold your center without matching their static — **your steadiness under lightning is the skill this opposition is installing**, and once installed, it makes you the calm one in every storm that matters." },
  "mars-neptune-conjunction": { title: "Mars conjunct Neptune", body: "Your will works like water: indirect, imaginative, most powerful when it **flows toward a vision** rather than a target. Straight-line ambition confuses you — five-year plans dissolve in your hands — but inspired action does not: when the work touches meaning, you can labor tirelessly, almost selflessly. You act best on intuition, timing, and dream-logic that spreadsheet people find mystifying and later call genius.\n\nGive your drive a dream worth serving and it becomes quietly unstoppable; deny it meaning and it evaporates into procrastination or escape. The practice is **choosing your devotion consciously** — art, healing, cause, craft — so the current has a bed to run in. And guard against glamorous drains: this aspect can pour heroic effort into mirages. **Vet the vision, then surrender to it.** That is your version of discipline." },
  "mars-neptune-square": { title: "Mars square Neptune", body: "Your drive keeps dissolving mid-reach: motivation evaporates, goals blur, effort leaks into daydream or escape. You have called it laziness in the privacy of your own head, and the name is wrong. **This is a will that refuses to work without meaning** — an engine that stalls on any fuel but the real thing. The fog is diagnostic, not moral.\n\nAttach your actions to something you genuinely believe in and watch the fog lift; it is almost embarrassing how quickly. The practice is meaning-first planning: find the why, then the task list, never the reverse. Guard the escape hatches — numbing, fantasy, the heroic plan that substitutes for the small step. Take one concrete action per day toward the inspired thing. Worked this way, the square yields **imagination with traction**: dreams that arrive in the world with your fingerprints on them." },
  "mars-neptune-opposition": { title: "Mars opposite Neptune", body: "You alternate between forcing and drifting, and other people often play the dreamer to your driver or the reverse — the vague partner who will not commit to a plan, the pushy one who tramples your intuition. Confusion around action is the recurring weather: whose plan, whose fault, whose fantasy. Efforts get sabotaged by miscommunication that no one can quite trace afterward.\n\nThe compass this opposition rewards is **clarity of intention, stated out loud**: here is what I am doing, here is why, here is what I need from you. Vagueness is where the trouble breeds — yours or theirs — so make explicitness your practice even when it feels unromantic. And integrate the poles: **act on your dreams and dream about your actions**. The driver and the mystic were always meant to share the wheel." },
  "mars-pluto-conjunction": { title: "Mars conjunct Pluto", body: "Your will has a nuclear core. When you commit, obstacles do not so much fall as get **metabolized** — absorbed, learned from, converted into force — and people sense the reserves even when you are quiet. You have survived things by sheer refusal, and your capacity for sustained, focused intensity frightens people who have never needed any. It is not aggression exactly. It is inevitability.\n\nPower like this needs **a worthy assignment**. Pointed at transformation — your own, your community's, some entrenched injustice — it moves what everyone said was immovable. Pointed at domination, it corrodes the wielder first. The practice is regular, honest audit: what is this force serving right now? And build rest into the campaign; even geological pressure benefits from release valves. **You are not too much. You are exactly enough for something large.**" },
  "mars-pluto-square": { title: "Mars square Pluto", body: "Your force meets forces: power struggles that feel primal, buried rage that surfaces at strange hours, the sense that winning requires total war or is not real winning. The grind is heavy — you rarely get to be casually assertive, because your assertion carries old survival charge, and small conflicts keep threatening to become existential ones. **Nobody handed you a manual for voltage like this.**\n\nHere is the manual's first page: intensity does not have to escalate to be effective. Trained — through discipline, therapy, sustained hard work, physical practice with real resistance in it — this square produces some of the most formidable people alive: unbreakable focus, fear metabolized into fuel. The practice is choosing the battles that deserve you and **walking, undiminished, from the ones that do not**. That walk is the power move." },
  "mars-pluto-opposition": { title: "Mars opposite Pluto", body: "Adversaries with real teeth show up in your story, and confrontation can feel existential rather than situational — the rival who plays dirty, the authority who wants submission, the conflict that somehow becomes about survival. The intensity of what opposes you is the clue: **it is often your own disowned ruthlessness in costume**, hired out to enemies because owning it felt too dangerous.\n\nIntegrate your power honestly and you stop needing opponents to prove it exists. Admit the full strength of your will — the part that could dominate, chose not to, and deserves credit for the choosing. Practice direct force in clean containers: negotiation, competition, advocacy with stakes. The opposition matures into something rare: **power that no longer needs a war to know itself**, and presence that ends most fights before they start." },
  "jupiter-saturn-conjunction": { title: "Jupiter conjunct Saturn", body: "Vision and structure are fused in you: the architect who dreams and the engineer who builds share one desk, and neither gets to leave early. You expand carefully and consolidate boldly — growth with load-bearing walls. This is the signature of people who **create things that last**: institutions, bodies of work, families of choice, reputations that compound rather than spike.\n\nThe rhythm to trust is **slow compounding** — your genius is unglamorous in any given quarter and unmistakable over a decade. Beware measuring yourself against the sprinters; their curve and yours are different instruments. The tending: make sure the structures serve the vision and not the reverse, and audit yearly for scaffolding that became a cage. Build on. **Time is not your obstacle; it is your medium.**" },
  "jupiter-saturn-square": { title: "Jupiter square Saturn", body: "Hope and doubt take turns driving, and every expansion in your life gets audited by an inner conservative — too big, then too careful, then too big again, the oscillation wearing you out from both directions. You have abandoned dreams for being unrealistic and regretted it; you have leapt without structure and paid for that too. **The grind is calibration in progress.**\n\nOver time it becomes judgment: the rare ability to grow at a sustainable rate, which most people never develop because they never had to reconcile the two drives. The practice is letting each voice have its proper job — Jupiter writes the vision, Saturn writes the schedule, neither edits the other's document. Expand, then consolidate, then expand again, on purpose. **Faith with receipts is your mature signature**, and it builds unshakable things." },
  "jupiter-saturn-opposition": { title: "Jupiter opposite Saturn", body: "You live between the open door and the fine print, and other people tend to embody whichever side you are not currently arguing for — optimists frustrate you with their missing math; pessimists deflate you with their missing faith. You keep being cast as the counterweight in every room, saying yes to the fearful and slow down to the bold, and the constant balancing can feel like never getting to be whole.\n\nBut both poles are yours, and the integration is the assignment: **believing big and building anyway, brick by brick**. Practice holding hope and rigor in the same sentence — this could be enormous, and here is the first small step. Let partnerships stop splitting the roles; bring your whole ledger to every table. Matured, this opposition makes you the rarest kind of counsel: **the one whose optimism can be trusted because it has been audited**." },
  "jupiter-uranus-conjunction": { title: "Jupiter conjunct Uranus", body: "You are wired for breakthroughs: sudden expansions, lucky lightning, doors that open sideways when the front entrance was locked. Your faith is in the new, and the future tends to reward you for arriving early — the technology adopted first, the idea backed before it was obvious, the reinvention that looked reckless and proved prophetic. **Freedom and growth are the same word in your dialect.**\n\nJust keep some ballast aboard: not every liftoff needs to abandon the ground crew, and your breakthroughs land better with a little continuity attached. The practice is harvesting each leap before chasing the next — document what worked, bank the gains, thank the people who held the rope. Your luck is real and partly manufactured: **you say yes to the strange door faster than anyone**. Keep saying it. Just furnish the rooms you win." },
  "jupiter-uranus-square": { title: "Jupiter square Uranus", body: "Your growth comes in jolts: sudden leaps, abrupt pivots, beliefs outgrown overnight and abandoned by morning. The expansion is real but the whiplash is too — your life keeps growing faster than your systems can absorb, and the people around you get motion sickness from updates they never saw coming. **The breakthroughs are not the problem; the missing shock absorbers are.**\n\nBuild flexible structures on purpose: plans with pivot points, commitments with review clauses, a communication habit that briefs your people before the swerve. Practice finishing the integration of one leap before initiating the next — insight unharvested is just noise with good branding. Worked consciously, this square becomes serial breakthrough as a lifestyle: **evolution that keeps its gains**, revolution that does not have to start from rubble each time." },
  "jupiter-uranus-opposition": { title: "Jupiter opposite Uranus", body: "You are pulled between the established path and the radical one — meaning-by-tradition and meaning-by-revolt — and other people keep dramatizing the choice for you: the institution that wants your loyalty, the renegade who wants your defection, each certain the other is wasting your life. You have played both roles yourself, orthodox in wild rooms and heretic in orthodox ones.\n\nThe mature move is **synthesis**: a philosophy open enough to keep updating, rooted enough to keep you steady. Take from tradition what actually holds; take from revolution what actually frees; discard both sides' costumes. Practice belonging without conformity — staying in rooms you can change, leaving rooms you cannot. What this opposition builds is genuinely needed: **a bridge person**, trusted by the keepers and the breakers alike, because you never lied to either." },
  "jupiter-neptune-conjunction": { title: "Jupiter conjunct Neptune", body: "Your faith runs oceanic: boundless compassion, mystical appetite, a working sense that everything is secretly connected — because for you, it observably is. You inspire people just by believing in front of them; hope is your ambient effect. The invisible world is not a theory to you but a neighborhood, and your generosity extends to people others have written off entirely.\n\nThe keel you need is **discernment**, since a heart this open will be tested by beautiful nonsense: the teacher who is mostly costume, the cause that is mostly incense, the promise that dissolves on contact. Testing your faith does not shrink it — **it is how faith becomes seaworthy**. Keep one rigorous friend on retainer; run the shimmering things past them. Your belief is a public utility. Guard the reservoir, and **pour freely from what is proven clean**." },
  "jupiter-neptune-square": { title: "Jupiter square Neptune", body: "Your hopes inflate past the visible horizon, and the grind comes at the reckoning: the guru disappoints, the windfall dissolves, the dream turns out to have needed a budget. You have believed extravagantly and invoiced painfully, and the disillusionments can tempt you to close the whole department of faith. **Do not — the faith is the gift; the missing verification was the flaw.**\n\nThis square is teaching your idealism to keep one eye open: inspiration first, then diligence, in that order, every time. Practice the split ledger — one page for the vision, one for the evidence — and let each grow at its own pace. Beware escapism dressed as spirituality; transcendence that skips your actual life is just avoidance with candles. Refined, this square yields **grounded wonder**: belief that survives audit, hope you can build on." },
  "jupiter-neptune-opposition": { title: "Jupiter opposite Neptune", body: "Meaning and mirage face off in your life, and you can swing between true belief and total disillusionment in a single season — the philosophy embraced whole, then abandoned whole, then replaced whole. Teachers and causes carry your projections until they buckle under the weight; other people keep playing prophet or fraud in your story, and sometimes both.\n\nBalance is **a faith you have personally tested**: small enough to be real, vast enough to matter. Stop outsourcing transcendence to the charismatic — build a practice from parts that have actually worked in your hands. Ask of every shining thing: what does this look like on a Tuesday? Keep what survives the question. Matured, this opposition makes you spiritually trustworthy — **someone whose sense of meaning has been through weather** and offers others shelter, not shimmer." },
  "jupiter-pluto-conjunction": { title: "Jupiter conjunct Pluto", body: "Your ambitions carry tectonic force: you do not want success so much as **transformation at scale** — systems changed, resources moved, the buried thing brought into the light and made useful. When you believe in something, resources gather around you almost gravitationally; people, money, and momentum seem to enlist. Influence is not something you chase. It accrues to you, which is exactly why it needs governance.\n\nThe stewardship question is the whole game: **power this concentrated must answer to something beyond appetite**. Write your accountability down — the purpose, the limits, the people allowed to tell you no — before the next expansion, not after. Watch the moment conviction stops taking questions; that is the tell. Aimed at genuine renewal, this conjunction moves history in miniature: **empires of the worthwhile**, built to hand on." },
  "jupiter-pluto-square": { title: "Jupiter square Pluto", body: "Your drive to matter grinds against forces of control — sometimes external gatekeepers, more often an internal compulsion that turns healthy ambition obsessive before you notice the shift. Enough stops registering; the goal metastasizes; you win the thing and immediately need the next thing, and the hunger starts to run you rather than serve you.\n\n**Ease is not the assignment; conscious power is.** The practice is auditing the ambition regularly: whom does this serve, what would satisfy it, and would I be proud to explain how I got it? Pursue influence you could defend out loud and the friction becomes ascent — this square, governed, produces people who change their fields permanently. Ungoverned, it just produces hunger with a résumé. **You get to choose, repeatedly, and the choosing is the power.**" },
  "jupiter-pluto-opposition": { title: "Jupiter opposite Pluto", body: "You meet power players and true believers — empires and undergrounds — and feel pulled to either convert or conquer whatever stands across from you. Confrontations with the powerful punctuate your story: the institution that wanted to absorb you, the magnate or movement that demanded allegiance, the negotiation that was secretly a duel. **The tension mirrors your own unfinished treaty between growth and control.**\n\nBalance arrives when your expansion empowers others instead of accumulating over them — when the measure of your success includes who else got stronger. Practice sharing power before it is demanded; audit your alliances for domination running in either direction. What this opposition builds, matured, is rare: **influence that liberates**, authority that other people are glad exists — the kind of power that does not require anyone else's diminishment to feel real." },
  "saturn-uranus-conjunction": { title: "Saturn conjunct Uranus", body: "The rule-keeper and the rule-breaker are fused in you, which makes you a rare thing: **a practical revolutionary**. You reform systems from inside, honoring what works while replacing what does not — the one who reads the whole rulebook precisely in order to rewrite it well. Institutions frustrate you and fascinate you; freedom without structure strikes you as noise, structure without freedom as slow death.\n\nChange built your way **tends to actually hold**, which is your quiet superpower: revolutions usually eat themselves, but yours come with foundations. The practice is patience with both camps — the traditionalists who read you as dangerous and the radicals who read you as compromised. You are neither. You are the bridge, and bridges take load from both directions. **Build the new inside the shell of the old, and hand people the keys.**" },
  "saturn-uranus-square": { title: "Saturn square Uranus", body: "Order and upheaval grind against each other in your life: structures you build get shaken, freedoms you claim demand new structure, and just when one is settled the other files a motion. You have been the steady one who suddenly quit, and the free one who suddenly craved rules — the alternation is the aspect, not a personal failing. **The tension is not a flaw in the plan; it is the plan.**\n\nYou are learning to renovate without demolition, and to demolish only what is truly condemned. The practice is scheduled revolution: regular reviews where the structures of your life reapply for their jobs, so change happens by appointment instead of by earthquake. What this square builds over time is invaluable — **judgment about what to keep and what to break**, which is the rarest form of both freedom and stability." },
  "saturn-uranus-opposition": { title: "Saturn opposite Uranus", body: "You keep standing between the old guard and the insurgents — cast as rebel in traditional rooms and traditionalist among rebels, fluent in both dialects and fully at home in neither. The casting is constant: institutions want your innovation but not your questions; movements want your rigor but not your caution. The awkward middle can feel like homelessness. **It is actually your post.**\n\nThe balance you are building — tested change, principled stability — is what both sides eventually need and neither can produce alone. Practice standing in the middle without apologizing for it: name what the tradition gets right to the radicals, name what must change to the keepers, and let both be annoyed. History is moved by exactly this position. **Hold it with pride; translators end more wars than armies do.**" },
  "saturn-neptune-conjunction": { title: "Saturn conjunct Neptune", body: "You are built to give dreams a skeleton. Vision without form frustrates you; form without vision deadens you; your work lives where the two shake hands — the composed music, the funded sanctuary, the discipline that serves something invisible. This is the signature of people who **make the ideal actual**: not by shrinking the dream but by teaching it to stand.\n\nDoubt and faith will alternate all your life — seasons where the dream feels absurd, seasons where the structure feels dead. **Keep building through both; that is the practice.** Neither weather is a verdict; both are just weather. The tending: do not let the doubt cancel projects it is only meant to refine, and do not let the vision excuse skipping the unglamorous middle steps. Brick by brick, you are making **something worthy of belief — and load-tested**." },
  "saturn-neptune-square": { title: "Saturn square Neptune", body: "Reality keeps auditing your dreams, and your dreams keep flooding your plans — a grind between what is and what could be that can leave you cynical on Monday and untethered by Friday. Structures you trusted dissolve; visions you served turn out to need budgets; the two departments of your life seem determined not to share files. **Disillusionment here is not failure; it is refinement.**\n\nEvery ideal that survives your own scrutiny becomes something you can actually build on — and that surviving remnant is worth more than the original shimmer. The practice is patience with the sorting: let dreams be tested without declaring the whole dreaming faculty bankrupt, and let plans stay porous enough to admit meaning. What this square produces, worked honestly, is rare: **working faith** — belief with foundations, structure with a soul." },
  "saturn-neptune-opposition": { title: "Saturn opposite Neptune", body: "You swing between rigid realism and total dissolve, and other people often carry the opposite pole: the flake to your planner, the bureaucrat to your mystic, each infuriating you with a quality that is secretly on your own payroll. Partnerships keep splitting the labor — one holds the boundaries, one holds the dream — until resentment renegotiates the contract.\n\n**Both poles are yours.** The balance is a working faith, structured enough to stand, porous enough to breathe: schedules with sabbath in them, budgets with a line for beauty, spiritual practice with actual appointments. Practice voicing both truths in the same conversation — here is the deadline, and here is the mystery — so nobody has to be your missing half. Integrated, this opposition makes you the rare adult who can **plan a miracle without strangling it**." },
  "saturn-pluto-conjunction": { title: "Saturn conjunct Pluto", body: "You were built for load-bearing work: enduring what breaks others and rebuilding from bedrock, sometimes more than once. Your relationship to power and limitation is deadly serious — you learned early that structures can fail catastrophically, and you have organized yourself around never being unprepared again. The resilience is nearly geological. People sense it and bring you their heaviest things, correctly.\n\nThe tending is **softness**: letting some things be light without auditing them for collapse. Not everything is load-bearing; some things are just pleasant, and you are allowed them without a stress test. Practice deliberate frivolity in small doses — it will feel irresponsible and it is medicine. Your depth is permanent; it does not need constant proving. **Strength that can also rest is the completed form**, and you are closer to it than you think." },
  "saturn-pluto-square": { title: "Saturn square Pluto", body: "Life keeps stress-testing your foundations, and the grind between control and transformation can feel merciless: the structure you built with such care meeting the force that insists it change, again, now. You have earned the right to be tired. But notice what the testing has already produced — **a person who does not break**, who rebuilds smarter each round, whose composure under pressure is not performance but geology.\n\nYour task now is **choosing renewal before circumstances choose it for you**: retiring the outgrown structure on your own schedule, releasing control where it has become grip. Fate here is material, not sentence — the pressure is workable, and you have been working it. What this square forges at full maturity is what communities are held up by: **someone who has been through it and stayed generous**." },
  "saturn-pluto-opposition": { title: "Saturn opposite Pluto", body: "Institutions and power brokers loom in your path, and struggles with authority can take on a fated weight — the system that seems designed to grind you specifically, the confrontation that feels older than its participants. What confronts you outside mirrors **a private negotiation between discipline and force**: your own order and your own depths, not yet on speaking terms, hiring external players for the drama.\n\nMake peace between them internally and the external sieges lose their grip. Practice wielding your intensity through legitimate structure — mastery, position, patient accumulation of standing — rather than against structure reflexively. And when real injustice does stand across from you, this aspect is exactly the equipment for the fight: **endurance plus depth**, pressure that outlasts empires. Just choose the fights that history would thank you for. **You have the tonnage; spend it on the worthy.**" },
  "uranus-neptune-conjunction": { title: "Uranus conjunct Neptune", body: "Innovation and imagination share one root system in you: your visions arrive both strange and luminous, ahead of their time and slightly out of focus — transmissions from a future that has not finished rendering. You belong to a generation dreaming new forms of meaning, and in you the signal runs personal: intuitions about how things could work that you cannot always source or footnote.\n\n**Grounding practices are what let the transmissions become real**: craft, body, deadline, the unglamorous disciplines that give a vision somewhere to land. Without them, this gift stays weather — beautiful, discussed, gone by evening. The practice is one act of translation per season: take the strangest true thing you perceive and build its smallest working model. **The future needs prototypes more than prophecies**, and you were built to supply both." },
  "uranus-neptune-square": { title: "Uranus square Neptune", body: "Your breakthroughs and your dreams grind against each other: clarity dissolves into fog, then lightning cuts through, then fog again — insight and uncertainty alternating like weather fronts. You can feel simultaneously ahead of your time and unable to explain what time you are ahead to. The oscillation is disorienting, and it is also **how vision gets tempered into something usable**.\n\nThe friction is teaching you to hold revelation loosely and test it often: act on the insight while it is bright, verify it while it is dim, and let the surviving remainder compound. **Insights you can act on beat revelations you can only admire** — one working experiment outranks a notebook of epiphanies. Keep the body involved; walking, water, and sleep are where your two signals reconcile. What survives the weather is the real transmission." },
  "uranus-neptune-opposition": { title: "Uranus opposite Neptune", body: "You are pulled between disruption and dissolution — the urge to break things open and the urge to drift beyond them entirely. One pole wants revolution now; the other wants transcendence instead; and other people keep striking you as either too radical or too vague, which is the reliable sign that **both currents are yours**, projected outward for easier viewing.\n\nYour balance point is **awakened imagination**: change that serves a dream, dreams that survive change. Practice pairing every rupture with a vision of what grows in the cleared space, and every reverie with one concrete act. Choose companions who hold the pole you are neglecting this season, and thank them instead of arguing. Integrated, this opposition makes you something the future is short on — **a visionary with a working relationship to consequence**." },
  "uranus-pluto-conjunction": { title: "Uranus conjunct Pluto", body: "You carry a generational charge: revolution and regeneration fused, the instinct to tear down what is dead and grow something unrecognizable in its place. In your personal life this reads as **periodic total reinvention** — identities, cities, callings composted whole, and a new self walking out of the mulch. People who knew you three versions ago describe someone you barely remember being.\n\nTrust the cycle; you are built for it, and the reinventions are not instability but metabolism. The tending is twofold: bring the people you love along with honest bulletins so your transformations stop reading as abandonments, and salvage before you burn — some timbers from the old self are load-bearing and worth carrying forward. **You are proof that a person can begin again completely.** For many people watching, that proof is the permission they needed." },
  "uranus-pluto-square": { title: "Uranus square Pluto", body: "Upheaval and transformation grind against each other in your story: changes arrive abrupt and deep at once, rarely gentle, often several at a time — the year everything moved, the season nothing held. You have learned that survival is not the ceiling; **it is the floor**, the baseline from which your actual life gets built. That knowledge cost you, and it is also capital.\n\nDirected consciously, this friction makes you an agent of change rather than its casualty: someone who initiates the deep shifts on purpose, at chosen moments, with an exit plan and a rebuilding budget. The practice is agency — when the ground starts moving, be the one who decides where to stand. And rest between earthquakes; even tectonic gifts need dormancy. **You were forged, not damaged. There is a difference, and you are it.**" },
  "uranus-pluto-opposition": { title: "Uranus opposite Pluto", body: "You feel history's tension personally: freedom against control, rupture against reconstruction, often played out through the institutions and movements around you — and sometimes across your own kitchen table. You keep finding yourself where the old power and the new impulse collide, holding an opinion each side finds insufficiently pure. The position is uncomfortable and **it is not an accident**.\n\nThe work is holding both truths: that things must break, and that something must hold. Practice being specific — which structure, which rupture, which timeline — because generalized revolution and generalized order are both just moods. People who can hold that balance become **hinge points**: the ones through whom change passes without becoming catastrophe. It is quiet, essential work. History rarely thanks the hinges, but **nothing turns without them**." },
  "neptune-pluto-conjunction": { title: "Neptune conjunct Pluto", body: "Dream and depth are fused at the root of your generation, and in you the mix runs personal: an instinct that **imagination is not escape but excavation** — that the dreamed thing and the buried thing are often the same thing, waiting. You sense what is dying and what wants to be born, sometimes decades before the obituaries and birth announcements run.\n\nMake art, or meaning, from the threshold: that is the assignment. Your gift is standing at the edge where forms dissolve and reading what comes next without flinching. The practice is keeping one foot in ordinary life — meals, friendships, small maintainable joys — so the threshold work has a home to return to. **The deep water is your workplace, not your residence.** Visit daily; live on shore; **bring back what you find**." },
  "neptune-pluto-square": { title: "Neptune square Pluto", body: "The mystic and the underworld negotiate in you, and the grind surfaces as cycles of disillusion and regeneration: faiths compost, deeper ones grow, and the composting can feel like loss until you notice the soil improving. What you believed at each stage was scaffolding for what you believe now — nothing was wasted, though plenty was surrendered. **Nothing about this is punishment.**\n\nYou are learning to let meaning die and return truer, which is a rare, quiet power: most people either grip their first faith forever or abandon faith entirely after the first collapse. You do neither. The practice is trusting the fallow seasons — when meaning goes quiet, tend the ordinary and wait; the deeper version is germinating. **Your beliefs are alive, which means they molt.** Let them, and **keep what returns**." },
  "neptune-pluto-opposition": { title: "Neptune opposite Pluto", body: "Transcendence and transformation face each other across your inner sky: the pull to dissolve and the pull to descend, escape and confrontation, the light that floats and the dark that digs. You may meet it as a lifelong tension between surrender and control — seasons of letting go entirely, seasons of gripping down to bedrock, and a suspicion that neither is the whole instruction.\n\nIt is not. The balance is **depth with a horizon**: facing the dark while keeping faith, surrendering what you cannot hold while transforming what you can. Practice pairing them deliberately — after every descent, something devotional; after every dissolution, something concrete. Other people will carry one pole for you until you claim both. Claimed, they make you rare: **someone who can go all the way down without losing the sky**." },
};
